from flask import Flask, redirect, request, session
import requests

app = Flask(__name__)

@app.route("/login")
def login():
    # Redirect user to authorization server for login
    return redirect("https://authorization-server.com/oauth/authorize?response_type=code&client_id=YOUR_CLIENT_ID&redirect_uri=http://localhost:5000/callback")

@app.route("/callback", methods=["GET"])
def callback():
    # Exchange authorization code for access token using requests.post()
    response = requests.post("https://authorization-server.com/oauth/token", data={"grant_type": "authorization_code", "client_id": "YOUR_CLIENT_ID", "client_secret": "YOUR_CLIENT_SECRET", "redirect_uri": "http://localhost:5000/callback", "code": request.args.get("code")})
    # Store access token in session
    session["access_token"] = response.json()["access_token"]
    return redirect("/")